import{c as n}from"./app.8935f5f1.js";const s={},a=n('<h1 id="nodejs-window下安装与配置淘宝镜像" tabindex="-1"><a class="header-anchor" href="#nodejs-window下安装与配置淘宝镜像" aria-hidden="true">#</a> nodejs window下安装与配置淘宝镜像</h1><p>1，前往nodejs官网下载安装软件，地址：https://nodejs.org/en/</p><p>2，点击下一步继续安装，安装完成，在命令输入：node -v,npm -v,查看版本，即是安装成功</p><p>3，随便在计算机哪个盘建一个全局目录，比如我的在E盘：E:\\nodejs\\node_global</p><p>4，设置nodejs全局目录，所有以全局安装的包都被安装在这，打开nodejs命令行窗口Node.js command prompt，</p><p>使用命令行设置：</p><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">npm</span> config <span class="token builtin class-name">set</span> cache <span class="token string">&quot;E:<span class="token entity" title="\\n">\\n</span>odejs<span class="token entity" title="\\n">\\n</span>ode_cache&quot;</span>\n\n<span class="token function">npm</span> config <span class="token builtin class-name">set</span> prefix <span class="token string">&quot;E:<span class="token entity" title="\\n">\\n</span>odejs<span class="token entity" title="\\n">\\n</span>ode_global&quot;</span>\n\n</code></pre></div><p><strong>设置环境变量</strong></p><p><strong>1》用户变量 path 中把 C:\\Users\\Administrator\\AppData\\Roaming\\npm;---改为----E:\\nodejs\\node_global</strong></p><p><strong>2》 在系统变量中 新增变量NODE_PATH----- E:\\nodejs\\node_global\\node_modules</strong></p><p><strong>3》系统变量中 path:C:\\Program Files\\nodejs;E:\\nodejs\\node_global\\node_modules;</strong></p><p>5,前往淘宝镜像官网 http://npm.taobao.org/，可查看安装cnpm包的命令</p><p>在命令行输入：</p><p><code>npm install -g cnpm --registry=https://registry.npm.taobao.org</code></p><p>6，安装完成</p><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span> -g cnpm --registry<span class="token operator">=</span>https://registry.npm.taobao.org\n</code></pre></div>',16);s.render=function(n,s){return a};export{s as default};
